import{_ as a,o as t,c as o,a4 as d}from"./chunks/framework.4M7SpZrd.js";const m=JSON.parse('{"title":"KubexFaceIndex — Indice Facial Web-Crawled","description":"","frontmatter":{},"headers":[],"relativePath":"motores/kubex-face-index.md","filePath":"motores/kubex-face-index.md"}'),i={name:"motores/kubex-face-index.md"};function s(r,e,n,c,l,u){return t(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="kubexfaceindex-—-indice-facial-web-crawled" tabindex="-1">KubexFaceIndex — Indice Facial Web-Crawled <a class="header-anchor" href="#kubexfaceindex-—-indice-facial-web-crawled" aria-label="Permalink to &quot;KubexFaceIndex — Indice Facial Web-Crawled&quot;">​</a></h1><h2 id="visao-geral" tabindex="-1">Visao Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visao Geral&quot;">​</a></h2><p>O KubexFaceIndex e o banco de dados proprietario de embeddings faciais extraidos de imagens encontradas na web por todos os motores do Kubex. Permite busca por similaridade facial em tempo real — o usuario faz upload de uma selfie e o sistema retorna todas as ocorrencias daquela face encontradas em sites monitorados.</p><p><strong>Modelo de negocio:</strong> Thumbnail (150px) visivel gratuitamente; URLs de origem requerem plano Pro+ (unlock por credito).</p><h2 id="arquitetura" tabindex="-1">Arquitetura <a class="header-anchor" href="#arquitetura" aria-label="Permalink to &quot;Arquitetura&quot;">​</a></h2><h3 id="stack" tabindex="-1">Stack <a class="header-anchor" href="#stack" aria-label="Permalink to &quot;Stack&quot;">​</a></h3><ul><li><strong>Vector DB:</strong> Milvus 2.4 (standalone, HNSW index, COSINE metric)</li><li><strong>Embedding model:</strong> InsightFace AntelopeV2 (512D float32)</li><li><strong>Metadata:</strong> PostgreSQL 16 (web_face_sources)</li><li><strong>Thumbnails:</strong> Cloudflare R2 (bucket kubex-faces, presigned URLs 1h)</li><li><strong>Worker:</strong> celery_face queue separada (Dockerfile.face, <strong>3 replicas</strong>)</li><li><strong>GPU:</strong> Habilitada por padrao (<code>INSIGHTFACE_GPU=true</code>), fallback automatico para CPU se CUDA indisponivel</li></ul><h3 id="pipeline-de-ingestao" tabindex="-1">Pipeline de Ingestao <a class="header-anchor" href="#pipeline-de-ingestao" aria-label="Permalink to &quot;Pipeline de Ingestao&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Crawler/8/9/13/15/18/27 encontra imagem</span></span>
<span class="line"><span>  → face_index_ingest_from_url (Celery, fila celery_face)</span></span>
<span class="line"><span>  → download (httpx, max 10MB)</span></span>
<span class="line"><span>  → decode (OpenCV)</span></span>
<span class="line"><span>  → face_detection (InsightFace, det_thresh=0.5)</span></span>
<span class="line"><span>  → [0 faces] → descarta</span></span>
<span class="line"><span>  → [1+ faces, max 10] → para cada face:</span></span>
<span class="line"><span>      • filtro qualidade (det_score &gt;= 0.5) + tamanho (&gt;= 64px)</span></span>
<span class="line"><span>      • opt-out check (Milvus kubex_face_optouts, similarity &gt; 0.90)</span></span>
<span class="line"><span>      • thumbnail_crop (face + 20% margem, resize 150px, JPEG 75%)</span></span>
<span class="line"><span>      • pHash (imagehash, 64-bit, para dedup)</span></span>
<span class="line"><span>      • dedup tiered:</span></span>
<span class="line"><span>          - &gt; 0.95: mesma foto → adiciona source, nao duplica</span></span>
<span class="line"><span>          - 0.85-0.95: mesma pessoa → agrupa sob mesmo face_id</span></span>
<span class="line"><span>          - &lt; 0.85: nova face → insere no Milvus</span></span>
<span class="line"><span>      • thumbnail → R2 (faces/{YYYY-MM}/{uuid}.jpg)</span></span>
<span class="line"><span>      • metadata → PostgreSQL (web_face_sources)</span></span></code></pre></div><h3 id="motores-com-hook-de-ingestao" tabindex="-1">Motores com Hook de Ingestao <a class="header-anchor" href="#motores-com-hook-de-ingestao" aria-label="Permalink to &quot;Motores com Hook de Ingestao&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Motor</th><th>Fonte</th><th>Hook</th></tr></thead><tbody><tr><td>2</td><td>Web crawler (.com.br)</td><td><code>face_index_ingest_from_url</code></td></tr><tr><td>8</td><td>Telegram (canais publicos)</td><td><code>face_index_ingest_from_bytes</code></td></tr><tr><td>9</td><td>Discord (servidores)</td><td><code>face_index_ingest_from_bytes</code></td></tr><tr><td>13</td><td>Reddit (subreddits BR)</td><td><code>face_index_ingest_from_bytes</code></td></tr><tr><td>15</td><td>Twitter/X</td><td><code>face_index_ingest_from_bytes</code></td></tr><tr><td>18</td><td>Instagram (perfis publicos)</td><td><code>face_index_ingest_from_bytes</code></td></tr><tr><td>27</td><td>Adult content crawler</td><td><code>face_index_ingest_from_url</code></td></tr></tbody></table><h2 id="milvus-collections" tabindex="-1">Milvus Collections <a class="header-anchor" href="#milvus-collections" aria-label="Permalink to &quot;Milvus Collections&quot;">​</a></h2><h3 id="kubex-web-faces" tabindex="-1">kubex_web_faces <a class="header-anchor" href="#kubex-web-faces" aria-label="Permalink to &quot;kubex_web_faces&quot;">​</a></h3><ul><li><strong>Schema:</strong> face_id (PK), embedding (FLOAT_VECTOR 512), source_domain, site_category, first_seen, image_phash, quality_score</li><li><strong>Index:</strong> HNSW (M=16, efConstruction=200, COSINE)</li><li><strong>Partitions:</strong> tube_sites, leak_sites, escort_sites, forums, imageboards, social_media, general_web</li></ul><h3 id="kubex-face-optouts" tabindex="-1">kubex_face_optouts <a class="header-anchor" href="#kubex-face-optouts" aria-label="Permalink to &quot;kubex_face_optouts&quot;">​</a></h3><ul><li><strong>Schema:</strong> optout_id (PK), embedding (FLOAT_VECTOR 512), email_hash, created_at</li><li><strong>Index:</strong> HNSW (M=16, efConstruction=200, COSINE)</li></ul><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><h3 id="busca-facial-usuario" tabindex="-1">Busca facial (usuario) <a class="header-anchor" href="#busca-facial-usuario" aria-label="Permalink to &quot;Busca facial (usuario)&quot;">​</a></h3><ul><li><code>POST /v1/face-search/web/detect</code> — Detecta faces na imagem, retorna thumbnails 240x240 para selecao</li><li><code>POST /v1/face-search/web</code> — Upload selfie + <code>face_index</code>, busca no indice (requer consentimento + Pro+)</li><li><code>POST /v1/face-search/web/unified</code> — Busca unificada (usa embedding armazenado ou selfie)</li><li><code>POST /v1/face-search/web/instant</code> — Busca instantanea Milvus-only (freemium, aceita <code>face_index</code>)</li><li><code>POST /v1/face-search/web/unlock</code> — Desbloquear URLs de um face_id</li></ul><h3 id="opt-out-publico-lgpd-—-pagina-opt-out-no-rodape-do-site" tabindex="-1">Opt-out (publico, LGPD — pagina /opt-out no rodape do site) <a class="header-anchor" href="#opt-out-publico-lgpd-—-pagina-opt-out-no-rodape-do-site" aria-label="Permalink to &quot;Opt-out (publico, LGPD — pagina /opt-out no rodape do site)&quot;">​</a></h3><ul><li><code>POST /v1/face-search/opt-out</code> — Enviar selfie + documento de identidade + email + nome (rate: 3/hora)</li><li><code>GET /v1/face-search/opt-out/confirm?token=xxx</code> — Confirmar via email</li></ul><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><ul><li><code>GET /v1/admin/face-index/stats</code> — Estatisticas gerais</li><li><code>GET /v1/admin/face-index/health</code> — Saude Milvus + collection</li><li><code>GET /v1/admin/face-index/top-domains</code> — Top 20 dominios</li><li><code>POST /v1/admin/face-index/force-stats</code> — Disparar stats manualmente</li><li><code>POST /v1/admin/face-index/force-dedup</code> — Disparar dedup manualmente</li><li><code>GET /v1/admin/face-index/opt-outs/stats</code> — Resumo de opt-outs</li><li><code>GET /v1/admin/face-index/opt-outs</code> — Listar opt-outs (paginado)</li><li><code>DELETE /v1/admin/face-index/opt-outs/{id}</code> — Rejeitar opt-out</li></ul><h2 id="celery-tasks" tabindex="-1">Celery Tasks <a class="header-anchor" href="#celery-tasks" aria-label="Permalink to &quot;Celery Tasks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Task</th><th>Schedule</th><th>Descricao</th></tr></thead><tbody><tr><td><code>face_index.ingest_from_url</code></td><td>On demand</td><td>Download + ingestao por URL</td></tr><tr><td><code>face_index.ingest_from_bytes</code></td><td>On demand</td><td>Ingestao por bytes (base64)</td></tr><tr><td><code>face_index.daily_stats</code></td><td>24h</td><td>Estatisticas diarias</td></tr><tr><td><code>face_index.verify_urls</code></td><td>7d</td><td>HEAD em 10% das URLs</td></tr><tr><td><code>face_index.cleanup_dead</code></td><td>30d</td><td>Remove faces sem URLs ativas (&gt;12 meses)</td></tr><tr><td><code>face_index.cleanup_search_logs</code></td><td>24h</td><td>Remove logs &gt;90 dias (LGPD)</td></tr><tr><td><code>face_index.refresh_optout_cache</code></td><td>1h</td><td>Recarrega cache Redis de opt-out embeddings</td></tr></tbody></table><h2 id="r2-storage-thumbnails" tabindex="-1">R2 Storage (Thumbnails) <a class="header-anchor" href="#r2-storage-thumbnails" aria-label="Permalink to &quot;R2 Storage (Thumbnails)&quot;">​</a></h2><ul><li><strong>Bucket:</strong> <code>kubex-faces</code> (separado de <code>kubex-evidence</code>)</li><li><strong>Key pattern:</strong> <code>faces/{YYYY-MM}/{uuid}.jpg</code></li><li><strong>Tamanho medio:</strong> ~8-12KB (150px, JPEG 75%)</li><li><strong>Acesso:</strong> Presigned URLs com expiracao de 1h</li><li><strong>Local (dev):</strong> <code>/tmp/kubex-faces/</code></li></ul><h2 id="lgpd-compliance" tabindex="-1">LGPD Compliance <a class="header-anchor" href="#lgpd-compliance" aria-label="Permalink to &quot;LGPD Compliance&quot;">​</a></h2><ol><li><strong>Opt-out gratuito</strong> com verificacao por email (impede abuso de remocao por terceiros)</li><li><strong>Indice opt-out separado</strong> (Milvus kubex_face_optouts) — consultado antes de cada ingestao</li><li><strong>Minimizacao:</strong> apenas embedding (2KB) + thumbnail crop (10KB); nunca a foto original</li><li><strong>Consentimento biometrico</strong> obrigatorio para buscar (FaceSearchConsent, Art. 11)</li><li><strong>Retencao:</strong> faces sem match ativo em 12 meses removidas automaticamente</li><li><strong>Anti-stalking:</strong> pHash da query armazenado (90 dias) para auditoria forense</li><li><strong>img_bytes deletados</strong> imediatamente apos extracao do embedding ([LGPD] tag no codigo)</li></ol><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h2><h3 id="usuario" tabindex="-1">Usuario <a class="header-anchor" href="#usuario" aria-label="Permalink to &quot;Usuario&quot;">​</a></h3><ul><li><code>/dashboard/protecao</code> — Upload selfie + resultados inline + opt-out link</li><li><code>/dashboard/perfil</code> — Gestao de consentimento biometrico (ativar/revogar)</li><li><code>/busca-facial/opt-out</code> — Pagina publica de remocao facial</li></ul><h3 id="admin-1" tabindex="-1">Admin <a class="header-anchor" href="#admin-1" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><ul><li><code>/admin/face-index</code> — Stats, health, top domains, acoes manuais, gestao de opt-outs</li></ul><h2 id="configuracao" tabindex="-1">Configuracao <a class="header-anchor" href="#configuracao" aria-label="Permalink to &quot;Configuracao&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variavel</th><th>Default</th><th>Descricao</th></tr></thead><tbody><tr><td>FACE_INDEX_ENABLED</td><td>true</td><td>Habilitar/desabilitar ingestao</td></tr><tr><td>FACE_INDEX_QUALITY_THRESHOLD</td><td>0.5</td><td>det_score minimo</td></tr><tr><td>FACE_INDEX_MIN_FACE_SIZE</td><td>64</td><td>Pixels minimos de face</td></tr><tr><td>FACE_INDEX_DEDUP_THRESHOLD</td><td>0.95</td><td>Dedup exato</td></tr><tr><td>FACE_INDEX_SAME_PERSON_THRESHOLD</td><td>0.85</td><td>Mesma pessoa</td></tr><tr><td>FACE_INDEX_OPTOUT_THRESHOLD</td><td>0.90</td><td>Bloqueio de re-indexacao</td></tr><tr><td>FACE_INDEX_SEARCH_THRESHOLD</td><td>0.6</td><td>Busca (resultados)</td></tr><tr><td>FACE_INDEX_MAX_FACES_PER_IMAGE</td><td>10</td><td>Max faces por imagem</td></tr><tr><td>FACE_INDEX_CLEANUP_RETENTION_DAYS</td><td>365</td><td>Retencao de faces mortas</td></tr><tr><td>R2_FACE_BUCKET_NAME</td><td>kubex-faces</td><td>Bucket R2 para thumbnails</td></tr><tr><td>FACE_SEARCH_QUERY_PHASH_RETENTION_DAYS</td><td>90</td><td>Retencao anti-stalking</td></tr><tr><td>FACE_SEARCH_MAX_SAME_FACE_PER_DAY</td><td>5</td><td>Limite anti-stalking</td></tr><tr><td>FACE_INDEX_INGEST_RATE_LIMIT</td><td>50/s</td><td>Rate limit configuravel de ingestao</td></tr><tr><td>MILVUS_SEARCH_EF</td><td>200</td><td>Parametro HNSW ef de busca (configuravel)</td></tr></tbody></table><h2 id="arquivos-principais" tabindex="-1">Arquivos Principais <a class="header-anchor" href="#arquivos-principais" aria-label="Permalink to &quot;Arquivos Principais&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Arquivo</th><th>Proposito</th></tr></thead><tbody><tr><td><code>app/engines/face_index.py</code></td><td>WebFaceIndex + OptOutIndex (Milvus singletons)</td></tr><tr><td><code>app/services/face_index_ingest.py</code></td><td>Pipeline de ingestao (extract + dedup + store)</td></tr><tr><td><code>app/tasks/face_index_tasks.py</code></td><td>Celery tasks (ingest, stats, verify, cleanup)</td></tr><tr><td><code>app/api/v1/face_search_web.py</code></td><td>Endpoints de busca facial (user)</td></tr><tr><td><code>app/api/v1/face_optout.py</code></td><td>Endpoints de opt-out (publico)</td></tr><tr><td><code>app/api/v1/admin/face_index_admin.py</code></td><td>Endpoints admin (stats, health, opt-outs)</td></tr><tr><td><code>app/models/web_face_source.py</code></td><td>Metadata de fontes (face_id, URL, thumbnail_key)</td></tr><tr><td><code>app/models/face_optout.py</code></td><td>Registro de opt-outs</td></tr><tr><td><code>app/models/face_search_log.py</code></td><td>Anti-stalking logs</td></tr><tr><td><code>app/services/storage_service.py</code></td><td>Upload/presigned URL para R2 (evidencias + faces)</td></tr><tr><td><code>app/services/email_service.py</code></td><td>Email de verificacao de opt-out</td></tr></tbody></table><h2 id="recursos-adicionais" tabindex="-1">Recursos Adicionais <a class="header-anchor" href="#recursos-adicionais" aria-label="Permalink to &quot;Recursos Adicionais&quot;">​</a></h2><ul><li><strong>Batch insert:</strong> <code>batch_insert_faces()</code> para insercao em lote (reduz round-trips gRPC)</li><li><strong>Rate limit configuravel:</strong> <code>FACE_INDEX_INGEST_RATE_LIMIT=50/s</code> (ajustavel por ambiente)</li><li><strong>HNSW ef configuravel:</strong> <code>MILVUS_SEARCH_EF=200</code> (maior valor = maior recall, maior latencia)</li><li><strong>Integracao com bulk crawling pipeline:</strong> imagens de bulk crawls alimentam automaticamente o indice facial</li><li><strong>Opt-out cache Redis:</strong> refresh a cada 1h via Celery Beat (<code>face_index.refresh_optout_cache</code>), elimina round-trip Milvus por face</li></ul>`,40)])])}const h=a(i,[["render",s]]);export{m as __pageData,h as default};
